const clientJs = "(function(){\n  \"use strict\";\n  var config=window.__FN_CONFIG__||{};\n  var page=window.__FN_PAGE__||{};\n  var copy=page.account||{};\n  var storageKey=\"football_network_session\";\n  var session=null;\n\n  function qs(selector,root){return (root||document).querySelector(selector);}\n  function qsa(selector,root){return Array.prototype.slice.call((root||document).querySelectorAll(selector));}\n  function escapeHtml(value){return String(value==null?\"\":value).replace(/[&<>\"']/g,function(char){return {\"&\":\"&amp;\",\"<\":\"&lt;\",\">\":\"&gt;\",'\"':\"&quot;\",\"'\":\"&#039;\"}[char];});}\n  function configured(){return Boolean(config.supabaseUrl&&config.anonKey);}\n  function base(path){return String(config.supabaseUrl||\"\").replace(/\\/$/,\"\")+path;}\n  function loadStored(){try{return JSON.parse(localStorage.getItem(storageKey)||\"null\");}catch(error){return null;}}\n  function saveStored(value){session=value; if(value)localStorage.setItem(storageKey,JSON.stringify(value)); else localStorage.removeItem(storageKey); updateAccountLink();}\n  function authMessage(error){return error&&error.message?error.message:(copy.authFailed||\"Authentication failed\");}\n  async function request(path,options,authenticated){\n    if(!configured())throw new Error(copy.serviceUnavailable||\"Service unavailable\");\n    options=options||{};\n    var headers=Object.assign({apikey:config.anonKey,\"content-type\":\"application/json\"},options.headers||{});\n    var token=authenticated&&session&&session.access_token?session.access_token:config.anonKey;\n    headers.Authorization=\"Bearer \"+token;\n    var response=await fetch(base(path),Object.assign({},options,{headers:headers}));\n    var raw=await response.text();\n    var data=null;\n    if(raw){try{data=JSON.parse(raw);}catch(error){data=raw;}}\n    if(!response.ok){var message=data&&(data.msg||data.message||data.error_description||data.hint);throw new Error(message||copy.serviceUnavailable||\"Request failed\");}\n    return data;\n  }\n  async function refreshSession(current){\n    if(!current||!current.refresh_token)return null;\n    try{\n      var next=await request(\"/auth/v1/token?grant_type=refresh_token\",{method:\"POST\",body:JSON.stringify({refresh_token:current.refresh_token})},false);\n      next.expires_at=Math.floor(Date.now()/1000)+(next.expires_in||3600);\n      saveStored(next);return next;\n    }catch(error){saveStored(null);return null;}\n  }\n  async function getSession(){\n    if(!session)session=loadStored();\n    if(session&&session.expires_at&&session.expires_at<Math.floor(Date.now()/1000)+60)session=await refreshSession(session);\n    updateAccountLink();return session;\n  }\n  function updateAccountLink(){\n    var link=qs(\"[data-user-link]\");if(!link)return;\n    var current=session||loadStored();\n    if(current&&current.user&&current.user.email)link.textContent=current.user.email.slice(0,1).toUpperCase();\n  }\n  function setMessage(element,message,type){if(!element)return;element.textContent=message||\"\";element.className=\"form-message\"+(type?\" \"+type:\"\");}\n  function slugify(value){return String(value||\"\").normalize(\"NFD\").replace(/[\\u0300-\\u036f]/g,\"\").toLowerCase().replace(/[^a-z0-9]+/g,\"-\").replace(/(^-|-$)/g,\"\");}\n  function roleLabel(code){var index=(page.roleCodes||[]).indexOf(code);return index>=0&&page.roles[index]?page.roles[index]:code||\"Football\";}\n\n  async function initAccount(){\n    var root=qs(\"[data-account-root]\");if(!root)return;\n    var authView=qs(\"[data-auth-view]\",root),memberView=qs(\"[data-member-view]\",root),message=qs(\"[data-account-message]\",root),authForm=qs(\"[data-auth-form]\",root),profileForm=qs(\"[data-profile-form]\",root);\n    var mode=\"signin\";\n    qsa(\"[data-auth-mode]\",root).forEach(function(button){button.addEventListener(\"click\",function(){mode=button.getAttribute(\"data-auth-mode\");qsa(\"[data-auth-mode]\",root).forEach(function(item){item.classList.toggle(\"active\",item===button);});qs(\".form-submit\",authForm).textContent=mode===\"signup\"?copy.signUp:copy.signIn;authForm.password.autocomplete=mode===\"signup\"?\"new-password\":\"current-password\";setMessage(message,\"\");});});\n    authForm.addEventListener(\"submit\",async function(event){event.preventDefault();setMessage(message,copy.loading);var form=new FormData(authForm);try{var path=mode===\"signup\"?\"/auth/v1/signup?redirect_to=\"+encodeURIComponent(location.origin+\"/\"+page.locale+\"/account\"):\"/auth/v1/token?grant_type=password\";var result=await request(path,{method:\"POST\",body:JSON.stringify({email:form.get(\"email\"),password:form.get(\"password\")})},false);if(result&&result.access_token){result.expires_at=Math.floor(Date.now()/1000)+(result.expires_in||3600);saveStored(result);await showMember();setMessage(message,\"\");}else setMessage(message,copy.checkEmail,\"success\");}catch(error){setMessage(message,authMessage(error),\"error\");}});\n    qs(\"[data-reset-password]\",root).addEventListener(\"click\",async function(){var email=authForm.email.value;if(!email){setMessage(message,copy.email,\"error\");return;}try{await request(\"/auth/v1/recover?redirect_to=\"+encodeURIComponent(location.origin+\"/\"+page.locale+\"/account\"),{method:\"POST\",body:JSON.stringify({email:email})},false);setMessage(message,copy.resetSent,\"success\");}catch(error){setMessage(message,authMessage(error),\"error\");}});\n    qs(\"[data-sign-out]\",root).addEventListener(\"click\",async function(){try{if(session)await request(\"/auth/v1/logout\",{method:\"POST\"},true);}catch(error){}saveStored(null);authView.classList.remove(\"hidden\");memberView.classList.add(\"hidden\");setMessage(message,\"\");});\n    profileForm.addEventListener(\"submit\",async function(event){event.preventDefault();setMessage(message,copy.saving);var form=new FormData(profileForm);try{var result=await request(\"/rest/v1/rpc/create_member_profile\",{method:\"POST\",body:JSON.stringify({p_display_name:form.get(\"displayName\"),p_slug:slugify(form.get(\"displayName\")),p_role_code:form.get(\"roleCode\"),p_bio:form.get(\"bio\"),p_city:form.get(\"city\"),p_location_text:form.get(\"country\"),p_preferred_locale:page.locale})},true);setMessage(message,copy.saved,\"success\");showProfileReady(result,{display_name:form.get(\"displayName\"),primary_role_code:form.get(\"roleCode\"),slug:result.slug});}catch(error){setMessage(message,authMessage(error),\"error\");}});\n    async function showMember(){var current=await getSession();if(!current){authView.classList.remove(\"hidden\");memberView.classList.add(\"hidden\");return;}authView.classList.add(\"hidden\");memberView.classList.remove(\"hidden\");qs(\"[data-member-email]\",root).textContent=current.user&&current.user.email?current.user.email:\"\";try{var profiles=await request(\"/rest/v1/profiles?select=id,display_name,slug,primary_role_code,location_text,bio&user_id=eq.\"+encodeURIComponent(current.user.id)+\"&profile_type=eq.person&limit=1\",{method:\"GET\"},true);if(Array.isArray(profiles)&&profiles[0])showProfileReady(profiles[0],profiles[0]);}catch(error){setMessage(message,authMessage(error),\"error\");}}\n    function showProfileReady(result,profile){qs(\"[data-onboarding-view]\",root).classList.add(\"hidden\");var ready=qs(\"[data-profile-ready]\",root);ready.classList.remove(\"hidden\");qs(\"[data-profile-summary]\",ready).textContent=(profile.display_name||\"\")+\" · \"+roleLabel(profile.primary_role_code);var link=qs(\"[data-my-profile]\",ready);link.href=\"/\"+page.locale+\"/profiles/\"+(result.slug||profile.slug);}\n    await showMember();\n  }\n\n  async function initDirectory(){\n    var grid=qs(\"[data-profile-grid]\");if(!grid||!configured())return;\n    var status=qs(\"[data-directory-status]\");\n    try{var profiles=await request(\"/rest/v1/profiles?select=id,display_name,slug,bio,city,location_text,primary_role_code,verification_status&visibility=eq.public&order=created_at.desc&limit=24\",{method:\"GET\"},false);if(!Array.isArray(profiles)||!profiles.length)return;grid.innerHTML=profiles.map(function(profile){var locationText=[profile.city,profile.location_text].filter(Boolean).join(\", \");return '<a class=\"profile-card\" href=\"/'+page.locale+'/profiles/'+encodeURIComponent(profile.slug)+'\"><div class=\"profile-card-head\"><div class=\"avatar\">'+escapeHtml((profile.display_name||\"F\").slice(0,1))+'</div><span class=\"tag\">'+escapeHtml(profile.verification_status===\"verified\"?(page.coreVerified||\"\"):(page.open||\"\"))+'</span></div><h3>'+escapeHtml(profile.display_name)+'</h3><p class=\"muted\">'+escapeHtml(roleLabel(profile.primary_role_code))+(locationText?' · '+escapeHtml(locationText):'')+'</p><div class=\"tag-row\"><span class=\"tag\">'+escapeHtml(roleLabel(profile.primary_role_code))+'</span><span class=\"tag\">Football Network</span></div></a>';}).join(\"\");if(status)status.textContent=copy.liveMembers+\" · \"+profiles.length;}catch(error){if(status)status.textContent=\"\";}\n  }\n\n  async function initProfile(){\n    var root=qs(\"[data-profile-root]\");if(!root)return;\n    var slug=root.getAttribute(\"data-profile-slug\"),button=qs(\"[data-connect-profile]\",root),feedback=qs(\"[data-connection-feedback]\",root),targetId=\"\";\n    if(configured()){try{var profiles=await request(\"/rest/v1/profiles?select=id,display_name,slug,bio,city,location_text,primary_role_code,verification_status&slug=eq.\"+encodeURIComponent(slug)+\"&limit=1\",{method:\"GET\"},false);if(Array.isArray(profiles)&&profiles[0]){var profile=profiles[0];targetId=profile.id;qs(\"[data-profile-name]\",root).textContent=profile.display_name;qs(\"[data-profile-avatar]\",root).textContent=(profile.display_name||\"F\").slice(0,1);qs(\"[data-profile-role]\",root).textContent=roleLabel(profile.primary_role_code);qs(\"[data-profile-location]\",root).textContent=[profile.city,profile.location_text].filter(Boolean).length?\" · \"+[profile.city,profile.location_text].filter(Boolean).join(\", \"):\"\";qs(\"[data-profile-bio]\",root).textContent=profile.bio||\"\";qs(\"[data-profile-expertise]\",root).textContent=roleLabel(profile.primary_role_code)+\" · International network\";qs(\"[data-profile-verification]\",root).textContent=profile.verification_status===\"verified\"?(page.coreVerified||\"\"):(page.open||\"\");}}catch(error){}}\n    if(button)button.addEventListener(\"click\",async function(){if(!targetId){feedback.textContent=copy.demoConnection;return;}var current=await getSession();if(!current){feedback.textContent=copy.connectionLogin;setTimeout(function(){location.href=\"/\"+page.locale+\"/account\";},900);return;}try{var result=await request(\"/rest/v1/rpc/request_connection\",{method:\"POST\",body:JSON.stringify({target_profile:targetId})},true);feedback.textContent=result&&result.created?copy.connectionSent:(result&&result.reason===\"profile_required\"?copy.profileRequired:copy.connectionExists);}catch(error){feedback.textContent=authMessage(error);}});\n  }\n\n  async function initNetwork(){\n    var root=qs(\"[data-network-root]\");if(!root)return;\n    var networkCopy=page.network||{},gate=qs(\"[data-network-gate]\",root),dashboard=qs(\"[data-network-dashboard]\",root),feedback=qs(\"[data-network-feedback]\",root),ownProfile=null;\n    function setCount(name,value){var total=qs(\"[data-network-\"+name+\"-total]\",root),badge=qs(\"[data-network-\"+name+\"-badge]\",root);if(total)total.textContent=String(value);if(badge)badge.textContent=String(value);}\n    function empty(text){return '<div class=\"network-empty\">'+escapeHtml(text)+\"</div>\";}\n    function personRow(connection,profile,type){\n      var locationText=[profile.city,profile.location_text].filter(Boolean).join(\", \"),actions=\"\";\n      if(type===\"incoming\")actions='<button class=\"primary\" type=\"button\" data-network-decision=\"'+connection.id+'\" data-decision=\"accepted\">'+escapeHtml(networkCopy.accept)+'</button><button type=\"button\" data-network-decision=\"'+connection.id+'\" data-decision=\"rejected\">'+escapeHtml(networkCopy.decline)+\"</button>\";\n      else if(type===\"outgoing\")actions='<span class=\"network-state\">'+escapeHtml(networkCopy.pending)+\"</span>\";\n      else actions='<a href=\"/'+page.locale+'/profiles/'+encodeURIComponent(profile.slug)+'\">'+escapeHtml(networkCopy.view)+\"</a>\";\n      return '<article class=\"network-row\"><div class=\"network-avatar\">'+escapeHtml((profile.display_name||\"F\").slice(0,1))+'</div><div class=\"network-person\"><h3>'+escapeHtml(profile.display_name||\"Football Network\")+'</h3><p>'+escapeHtml(roleLabel(profile.primary_role_code))+(locationText?' · '+escapeHtml(locationText):\"\")+'</p></div><div class=\"network-row-actions\">'+actions+\"</div></article>\";\n    }\n    async function loadNetwork(){\n      setMessage(feedback,networkCopy.loading);\n      var current=await getSession();\n      if(!current){gate.classList.remove(\"hidden\");dashboard.classList.add(\"hidden\");return;}\n      try{\n        var mine=await request(\"/rest/v1/profiles?select=id,display_name,slug&user_id=eq.\"+encodeURIComponent(current.user.id)+\"&profile_type=eq.person&limit=1\",{method:\"GET\"},true);\n        if(!Array.isArray(mine)||!mine[0]){qs(\"[data-network-gate-title]\",root).textContent=networkCopy.profileRequired;qs(\"[data-network-gate-text]\",root).textContent=\"\";var action=qs(\"[data-network-gate-action]\",root);action.textContent=networkCopy.createProfile;action.href=\"/\"+page.locale+\"/account\";gate.classList.remove(\"hidden\");dashboard.classList.add(\"hidden\");setMessage(feedback,\"\");return;}\n        ownProfile=mine[0];gate.classList.add(\"hidden\");dashboard.classList.remove(\"hidden\");\n        var connections=await request(\"/rest/v1/connections?select=id,requester_profile_id,receiver_profile_id,status,created_at&or=(requester_profile_id.eq.\"+ownProfile.id+\",receiver_profile_id.eq.\"+ownProfile.id+\")&order=created_at.desc\",{method:\"GET\"},true);\n        connections=Array.isArray(connections)?connections:[];\n        var otherIds=Array.from(new Set(connections.map(function(item){return item.requester_profile_id===ownProfile.id?item.receiver_profile_id:item.requester_profile_id;}).filter(Boolean)));\n        var profiles=[];\n        if(otherIds.length)profiles=await request(\"/rest/v1/profiles?select=id,display_name,slug,primary_role_code,city,location_text,verification_status&id=in.(\"+otherIds.join(\",\")+\")\",{method:\"GET\"},true);\n        var profileMap={};(Array.isArray(profiles)?profiles:[]).forEach(function(profile){profileMap[profile.id]=profile;});\n        function pair(item){var otherId=item.requester_profile_id===ownProfile.id?item.receiver_profile_id:item.requester_profile_id;return {connection:item,profile:profileMap[otherId]};}\n        var incoming=connections.filter(function(item){return item.status===\"pending\"&&item.receiver_profile_id===ownProfile.id;}).map(pair).filter(function(item){return item.profile;});\n        var outgoing=connections.filter(function(item){return item.status===\"pending\"&&item.requester_profile_id===ownProfile.id;}).map(pair).filter(function(item){return item.profile;});\n        var accepted=connections.filter(function(item){return item.status===\"accepted\";}).map(pair).filter(function(item){return item.profile;});\n        setCount(\"incoming\",incoming.length);setCount(\"outgoing\",outgoing.length);setCount(\"connections\",accepted.length);\n        qs(\"[data-network-incoming-list]\",root).innerHTML=incoming.length?incoming.map(function(item){return personRow(item.connection,item.profile,\"incoming\");}).join(\"\"):empty(networkCopy.emptyIncoming);\n        qs(\"[data-network-outgoing-list]\",root).innerHTML=outgoing.length?outgoing.map(function(item){return personRow(item.connection,item.profile,\"outgoing\");}).join(\"\"):empty(networkCopy.emptyOutgoing);\n        qs(\"[data-network-connections-list]\",root).innerHTML=accepted.length?accepted.map(function(item){return personRow(item.connection,item.profile,\"accepted\");}).join(\"\"):empty(networkCopy.emptyConnections);\n        setMessage(feedback,\"\");\n      }catch(error){setMessage(feedback,networkCopy.loadError||authMessage(error),\"error\");}\n    }\n    root.addEventListener(\"click\",async function(event){var button=event.target.closest(\"[data-network-decision]\");if(!button)return;button.disabled=true;try{var decision=button.getAttribute(\"data-decision\");var result=await request(\"/rest/v1/rpc/respond_to_connection\",{method:\"POST\",body:JSON.stringify({connection_id:button.getAttribute(\"data-network-decision\"),decision:decision})},true);if(result&&result.updated){setMessage(feedback,decision===\"accepted\"?networkCopy.accepted:networkCopy.declined,\"success\");await loadNetwork();}else setMessage(feedback,networkCopy.loadError,\"error\");}catch(error){setMessage(feedback,authMessage(error),\"error\");button.disabled=false;}});\n    await loadNetwork();\n  }\n\n\n  document.addEventListener(\"DOMContentLoaded\",async function(){session=loadStored();updateAccountLink();await getSession();await initAccount();await initDirectory();await initProfile();await initNetwork();});\n})();";

const pageRenderers = {home:homePage,network:networkPage,profiles:profilesPage,organizations:organizationsPage,opportunities:opportunitiesPage,messages:messagesPage,premium:premiumPage,account:accountPage};

const render = (request, locale, route, slug = "", env = {}) => {
  const tr = i18n[locale];
  const core = coreI18n[locale];
  const account = accountI18n[locale];
  const network = networkI18n[locale];
  const url = new URL(request.url);
  const activeRoute = route === "profile" ? "profiles" : route;
  const routePath = route === "home" ? "" : route === "profile" ? `/profiles/${slug}` : `/${route}`;
  const alternates = localeOrder.map(code => `<link rel="alternate" hreflang="${code}" href="${url.origin}/${code}${routePath}">`).join("");
  const nav = tr.nav.map((label,index) => `<a class="${activeRoute === navRoutes[index] ? "active" : ""}" href="${href(locale,navRoutes[index])}">${label}</a>`).join("");
  const main = route === "profile" ? profileDetailPage(locale,tr,slug) : pageRenderers[route](locale,tr);
  const pageTitle = route === "profile" ? (profilesData.find(([name]) => slugifyProfile(name) === slug)?.[0] || slug) : route === "premium" ? core.premiumTitle : route === "account" ? account.accountTitle : tr.nav[navRoutes.indexOf(route)];
  const publicConfig = JSON.stringify({supabaseUrl:env.NEXT_PUBLIC_SUPABASE_URL || "",anonKey:env.NEXT_PUBLIC_SUPABASE_ANON_KEY || ""}).replace(/</g,"\\u003c");
  const pageConfig = JSON.stringify({locale,route,slug,account,network,roles:tr.roles,roleCodes:["player","head_coach","assistant_coach","fitness_coach","sports_doctor","physiotherapist","osteopath","video_analyst","scout","agent","club_president","general_manager","marketing_manager","logistics_manager","administrative_manager"],open:tr.open,coreVerified:core.verified}).replace(/</g,"\\u003c");
  return `<!doctype html><html lang="${locale}" dir="${tr.dir}"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Football Network · ${pageTitle}</title><meta name="description" content="${tr.mission}"><link rel="canonical" href="${url.origin}/${locale}${routePath}">${alternates}<link rel="alternate" hreflang="x-default" href="${url.origin}/en${routePath}"><link rel="preconnect" href="https://fonts.googleapis.com"><link rel="preconnect" href="https://fonts.gstatic.com" crossorigin><link href="https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&family=Noto+Sans+Arabic:wght@400;500;600;700&display=swap" rel="stylesheet"><style>${css}${coreCss}</style></head><body><div class="shell"><header class="network-topbar"><a class="brand-lockup" href="${href(locale)}"><span class="brand-mark">FN</span><span>Football Network</span></a><div class="global-search"><input placeholder="${tr.search}" aria-label="${tr.search}"></div><nav class="top-nav">${nav}</nav><div class="top-actions">${languageSelect(locale,routePath)}<button>${tr.notifications}</button><a class="account-trigger" href="/${locale}/account" data-user-link>${tr.you}</a></div></header><div class="layout-frame">${leftRail(locale,tr)}<main class="center-scroll"><div class="app-status"><strong>Football Network</strong><span>${tr.bridge}</span></div>${main}</main>${rightRail(locale,tr)}</div></div><script>window.__FN_CONFIG__=${publicConfig};window.__FN_PAGE__=${pageConfig};${clientJs}</script></body></html>`;
};

const detectLocale = request => {
  const header = request.headers.get("accept-language") || "";
  const candidates = header.split(",").map(item => item.split(";")[0].trim().toLowerCase().split("-")[0]);
  return candidates.find(code => localeOrder.includes(code)) || "fr";
};

export default {
  async fetch(request, env = {}) {
    const url = new URL(request.url);
    const parts = url.pathname.split("/").filter(Boolean);
    const legacyRoutes = {players:"profiles",clubs:"organizations",opportunities:"opportunities",messages:"messages"};
    if (!parts.length) return Response.redirect(new URL(`/${detectLocale(request)}`,url),302);
    if (!localeOrder.includes(parts[0])) {
      const route = legacyRoutes[parts[0]] || "";
      return Response.redirect(new URL(`/${detectLocale(request)}${route ? `/${route}` : ""}`,url),302);
    }
    const locale = parts[0];
    if (parts[1] === "profiles" && parts[2]) {
      return new Response(render(request,locale,"profile",parts[2],env),{headers:{"content-type":"text/html; charset=utf-8","cache-control":"public, max-age=60"}});
    }
    const requested = legacyRoutes[parts[1]] || parts[1] || "home";
    const route = [...routeNames,"premium","account"].includes(requested) ? requested : "home";
    return new Response(render(request,locale,route,"",env),{headers:{"content-type":"text/html; charset=utf-8","cache-control":"public, max-age=60"}});
  }
};
